select.if:
select curDept.id, od.code as parentCode, curDept.code, curDept.name, curDept.dept_type as deptType, curDept.description, curDept.full_path as fullPath, curDept.lay_no as layNo, curDept.sort, curDept.valid, curDept.modify_time as modifyTime, company.code as companyCode, company.full_name as companyFullName, company.short_name as companyShortName from org_department curDept left join org_company company on curDept.company_id = company.id left join org_department od on curDept.parent_id = od.id
where curDept.modify_time > #{modifyTime}
where curDept.valid =1
order by curDept.lay_no, curDept.sort
limit #{offset}, #{pageSize}

select * from (select TMP.*, ROWNUM ROW_ID from (select curDept.id, curDept.code, curDept.name, curDept.dept_type as deptType, curDept.description, curDept.full_path as fullPath, curDept.lay_no as layNo, curDept.sort,
curDept.valid, curDept.modify_time as modifyTime, company.code as companyCode, company.full_name as companyFullName, company.short_name as companyShortName
from org_department curDept left join org_company company on curDept.company_id = company.id

    where to_char(curDept.modify_time ,'yyyy-mm-dd hh24:mi:ss') > #{modifyTime}


    where curDept.valid =1

order by curDept.lay_no, curDept.sort) TMP

    where ROWNUM <= #{current}*#{pageSize}

) where ROW_ID >

        #{offset}


    0

select * from (select ROW_NUMBER() over (order by layNo,sort) as tempId, * from (
select curDept.id, od.code as parentCode, curDept.code, curDept.name, curDept.dept_type as deptType, curDept.description, curDept.full_path as fullPath, curDept.lay_no as layNo, curDept.sort,
curDept.valid, curDept.modify_time as modifyTime, company.code as companyCode, company.full_name as companyFullName, company.short_name as companyShortName
from org_department curDept left join org_company company on curDept.company_id = company.id left join org_department od on curDept.parent_id = od.id

    where curDept.modify_time > #{modifyTime}


    where curDept.valid =1

)as a) as a where a.tempId between #{sqlserverOffset} and #{pointer}

select count(*) from org_department curDept left join org_company company on curDept.company_id = company.id left join org_department od on curDept.parent_id = od.id

    where curDept.modify_time > #{modifyTime}


    where curDept.valid =1

select count(*) from org_department curDept left join org_company company on curDept.company_id = company.id

    where to_char(curDept.modify_time ,'yyyy-mm-dd hh24:mi:ss') > #{modifyTime}


    where curDept.valid =1

mapper.select:
select curDept.id, od.code as parentCode, curDept.parent_id as parentId, curDept.code, curDept.name, curDept.dept_type as deptType, curDept.description, curDept.full_path as fullPath, curDept.lay_no as layNo, curDept.sort,
curDept.valid, curDept.modify_time as modifyTime, company.code as companyCode, company.full_name as companyFullName, company.short_name as companyShortName
from org_department curDept left join org_company company on curDept.company_id = company.id left join org_department od on curDept.parent_id = od.id  where curDept.valid = 1 and curDept.code = #{departmentCode }

select orgManager.org_id as deptId, person.code as managerCode, person.name as managerName
from org_manager orgManager join org_person person on orgManager.manager_id = person.id where orgManager.org_id in

    #{item}

select.if:
select * from (select TMP.*, ROWNUM ROW_ID from (select curDept.id, curDept.code, curDept.name, curDept.dept_type as deptType, curDept.valid, curDept.full_path as fullPath, parentDept.code as parentCode, company.code as companyCode,
company.full_name as companyFullName, company.short_name as companyShortName from org_department curDept
left join org_company company on curDept.company_id = company.id
left join org_department parentDept on curDept.parent_id = parentDept.id
where company.id = #{companyId} and curDept.valid = 1
order by curDept.lay_no, curDept.sort) TMP

    where ROWNUM <= #{current}*#{pageSize}

) where ROW_ID >

    #{offset}


    0
